static int create_ppc_opcodes (CPUPPCState *env, ppc_def_t *def)

{

    opcode_t *opc, *start, *end;



    fill_new_table(env->opcodes, 0x40);

#if defined(PPC_DUMP_CPU)

    printf("* PowerPC instructions for PVR %08x: %s flags %016" PRIx64

           " %08x\n",

           def->pvr, def->name, def->insns_flags, def->flags);

#endif

    if (&opc_start < &opc_end) {

        start = &opc_start;

        end = &opc_end;

    } else {

        start = &opc_end;

        end = &opc_start;

    }

    for (opc = start + 1; opc != end; opc++) {

        if ((opc->handler.type & def->insns_flags) != 0) {

            if (register_insn(env->opcodes, opc) < 0) {

                printf("*** ERROR initializing PowerPC instruction "

                       "0x%02x 0x%02x 0x%02x\n", opc->opc1, opc->opc2,

                       opc->opc3);

                return -1;

            }

#if defined(PPC_DUMP_CPU)

            if (opc1 != 0x00) {

                if (opc->opc3 == 0xFF) {

                    if (opc->opc2 == 0xFF) {

                        printf(" %02x -- -- (%2d ----) : %s\n",

                               opc->opc1, opc->opc1, opc->oname);

                    } else {

                        printf(" %02x %02x -- (%2d %4d) : %s\n",

                               opc->opc1, opc->opc2, opc->opc1, opc->opc2,

                               opc->oname);

                    }

                } else {

                    printf(" %02x %02x %02x (%2d %4d) : %s\n",

                           opc->opc1, opc->opc2, opc->opc3,

                           opc->opc1, (opc->opc3 << 5) | opc->opc2,

                           opc->oname);

                }

            }

#endif

        }

    }

    fix_opcode_tables(env->opcodes);

    fflush(stdout);

    fflush(stderr);



    return 0;

}

static void smp_parse(const char *optarg)

{

    int smp, sockets = 0, threads = 0, cores = 0;

    char *endptr;

    char option[128];



    smp = strtoul(optarg, &endptr, 10);

    if (endptr != optarg) {

        if (*endptr == ',') {

            endptr++;

        }

    }

    if (get_param_value(option, 128, "sockets", endptr) != 0)

        sockets = strtoull(option, NULL, 10);

    if (get_param_value(option, 128, "cores", endptr) != 0)

        cores = strtoull(option, NULL, 10);

    if (get_param_value(option, 128, "threads", endptr) != 0)

        threads = strtoull(option, NULL, 10);

    if (get_param_value(option, 128, "maxcpus", endptr) != 0)

        max_cpus = strtoull(option, NULL, 10);



    /* compute missing values, prefer sockets over cores over threads */

    if (smp == 0 || sockets == 0) {

        sockets = sockets > 0 ? sockets : 1;

        cores = cores > 0 ? cores : 1;

        threads = threads > 0 ? threads : 1;

        if (smp == 0) {

            smp = cores * threads * sockets;

        }

    } else {

        if (cores == 0) {

            threads = threads > 0 ? threads : 1;

            cores = smp / (sockets * threads);

        } else {

            threads = smp / (cores * sockets);

        }

    }

    smp_cpus = smp;

    smp_cores = cores > 0 ? cores : 1;

    smp_threads = threads > 0 ? threads : 1;

    if (max_cpus == 0)

        max_cpus = smp_cpus;

}

